        // SetGroupCmfItem()
        //       - Set Group / Cmf Property to control
        // Return Value
        //       -
        // Arguments
        //        -
        private void SetGroupCmfItem()
        {
            string[] sGrpTableName = new string[10];

            sGrpTableName[0] = MPGC.MP_GCM_CHT_GRP_1;
            sGrpTableName[1] = MPGC.MP_GCM_CHT_GRP_2;
            sGrpTableName[2] = MPGC.MP_GCM_CHT_GRP_3;
            sGrpTableName[3] = MPGC.MP_GCM_CHT_GRP_4;
            sGrpTableName[4] = MPGC.MP_GCM_CHT_GRP_5;
            sGrpTableName[5] = MPGC.MP_GCM_CHT_GRP_6;
            sGrpTableName[6] = MPGC.MP_GCM_CHT_GRP_7;
            sGrpTableName[7] = MPGC.MP_GCM_CHT_GRP_8;
            sGrpTableName[8] = MPGC.MP_GCM_CHT_GRP_9;
            sGrpTableName[9] = MPGC.MP_GCM_CHT_GRP_10;

            MPCR.SetGRPItem(MPGC.MP_GRP_CHART, "lblGrp", "cdvGrp", grpGroup, sGrpTableName);
            MPCR.SetCMFItem(MPGC.MP_CMF_CHART, "lblCmf", "cdvCmf", grpCMF);

        }

        // CheckCondition()
        //       - Check the conditions before transaction
        // Return Value
        //       - Boolean : True or False
        // Arguments
        //       - ByVal FuncName As String : Function Name
        //
        private bool CheckCondition(char FuncName)
        {

            try
            {
                if (txtChart.Text == "")
                {
                    MPCF.ShowMsgBox(MPCF.GetMessage(108));
                    txtChart.Focus();
                    return false;
                }

                switch (FuncName)
                {
                    case MPGC.MP_STEP_CREATE:

                        if (rbnLot.Checked == false && rbnResource.Checked == false)
                        {
                            MPCF.ShowMsgBox(MPCF.GetMessage(108));
                            rbnLot.Focus();
                            return false;
                        }
                        /* Material, Resource도 선택 조건에 포함시킴 - LAVERWON (2008/02/22)
                        if (rbnLot.Checked == true)
                        {
                            if (cdvMaterial.CheckValue() == false) return false;
                        }
                        else if (rbnResource.Checked == true)
                        {
                            if (cdvResID.Text == "")
                            {
                                MPCF.ShowMsgBox(MPCF.GetMessage(108));
                                cdvResID.Focus();
                                return false;
                            }
                        }
                        */
                        if (cdvCharID.Visible == true)
                        {
                            if (cdvCharID.Text == "")
                            {
                                MPCF.ShowMsgBox(MPCF.GetMessage(108));
                                cdvCharID.Focus();
                                return false;
                            }
                        }
                        if (txtUnitCount.ReadOnly == false)
                        {
                            if (txtUnitCount.Text == "")
                            {
                                MPCF.ShowMsgBox(MPCF.GetMessage(108));
                                txtUnitCount.Focus();
                                return false;
                            }
                            if (MPCF.CheckNumeric(txtUnitCount.Text) == false)
                            {
                                MPCF.ShowMsgBox(MPCF.GetMessage(116));
                                txtUnitCount.Focus();
                                return false;
                            }
                            if (MPCF.ToInt(txtUnitCount.Text) < 1)
                            {
                                /* Updated By YJJung 141110 Unit Count 가 입력 되지 않을 시, 잘못된 Error Message 발생 Bug Fix */
                                MPCF.ShowMsgBox(MPCF.GetMessage(141));
                                txtUnitCount.Focus();
                                return false;
                            }

                            if (MPCF.ToInt(txtUnitCount.Text) > 999999)
                            {
                                if (MPGV.gcLanguage == '2')
                                {
                                    MPCF.ShowMsgBox(MPCF.GetErrorMsgParse(236, "\'100\' ") + MPCF.GetMessage(236));
                                }
                                else
                                {
                                    MPCF.ShowMsgBox(MPCF.GetMessage(236) + " \'100\'");
                                }
                                txtUnitCount.Focus();
                                return false;
                            }
                        }
                        
                        if (cboGraphType.SelectedIndex == -1)
                        {
                            MPCF.ShowMsgBox(MPCF.GetMessage(108));
                            cboGraphType.Focus();
                            return false;
                        }
                        if (cboGraphType.SelectedIndex != MPCF.ToInt(eGraphType.P) && cboGraphType.SelectedIndex != MPCF.ToInt(eGraphType.C) && cboGraphType.SelectedIndex != MPCF.ToInt(eGraphType.U))
                        {
                            if (txtSampleSize.Text == "")
                            {
                                MPCF.ShowMsgBox(MPCF.GetMessage(108));
                                txtSampleSize.Focus();
                                return false;
                            }
                            if (MPCF.CheckNumeric(txtSampleSize.Text) == false)
                            {
                                MPCF.ShowMsgBox(MPCF.GetMessage(116));
                                txtSampleSize.Focus();
                                return false;
                            }
                            if (cboGraphType.SelectedIndex == MPCF.ToInt(eGraphType.XRS))
                            {
                                if (MPCF.ToInt(txtSampleSize.Text) < 1)
                                {
                                    if (MPGV.gcLanguage == '2')
                                    {
                                        MPCF.ShowMsgBox(MPCF.GetErrorMsgParse(234, "\'1\' ") + MPCF.GetMessage(234));
                                    }
                                    else
                                    {
                                        MPCF.ShowMsgBox(MPCF.GetMessage(234) + " \'1\'");
                                    }
                                    txtSampleSize.Focus();
                                    return false;
                                }
                            }
                            else
                            {
                                int i_unit_count = MPCF.ToInt(txtUnitCount.Text);
                                int i_sample_size = MPCF.ToInt(txtSampleSize.Text);

                                if (i_unit_count < 1) i_unit_count = 1;
                                if (i_sample_size < 1) i_sample_size = 1;

                                if (chkUseUnit.Checked == false)
                                {
                                    if (i_unit_count * i_sample_size < 2)
                                    {
                                        if (MPGV.gcLanguage == '2')
                                        {
                                            MPCF.ShowMsgBox(MPCF.GetErrorMsgParse(234, "\'2\' ") + MPCF.GetMessage(234));
                                        }
                                        else
                                        {
                                            MPCF.ShowMsgBox(MPCF.GetMessage(234) + " \'2\'");
                                        }
                                        txtSampleSize.Focus();
                                        return false;
                                    }
                                }
                                else
                                {
                                    if (i_sample_size < 2)
                                    {
                                        if (MPGV.gcLanguage == '2')
                                        {
                                            MPCF.ShowMsgBox(MPCF.GetErrorMsgParse(234, "\'2\' ") + MPCF.GetMessage(234));
                                        }
                                        else
                                        {
                                            MPCF.ShowMsgBox(MPCF.GetMessage(234) + " \'2\'");
                                        }
                                        txtSampleSize.Focus();
                                        return false;
                                    }
                                }
                            }
                            if (MPCF.ToInt(txtSampleSize.Text) > 999999)
                            {
                                if (MPGV.gcLanguage == '2')
                                {
                                    MPCF.ShowMsgBox(MPCF.GetErrorMsgParse(235, "\'999999\' ") + MPCF.GetMessage(235));
                                }
                                else
                                {
                                    MPCF.ShowMsgBox(MPCF.GetMessage(235) + " \'999999\'");
                                }
                                txtSampleSize.Focus();
                                return false;
                            }
                        }

                        if (txtPrecision.Text == "")
                        {
                            MPCF.ShowMsgBox(MPCF.GetMessage(108));
                            txtPrecision.Focus();
                            return false;
                        }
                        if (MPCF.ToInt(txtPrecision.Text) > 10)
                        {
                            if (MPGV.gcLanguage == '2')
                            {
                                MPCF.ShowMsgBox(MPCF.GetErrorMsgParse(236, "\'10\' ") + MPCF.GetMessage(236));
                            }
                            else
                            {
                                MPCF.ShowMsgBox(MPCF.GetMessage(236) + " \'10\'");
                            }
                            txtPrecision.Focus();
                            return false;
                        }
                        if (MPCF.ToInt(txtPrecision.Text) < 0)
                        {
                            MPCF.ShowMsgBox(MPCF.GetMessage(114));
                            txtPrecision.Focus();
                            return false;
                        }

                        if (txtConstant1.Visible == true)
                        {
                            if (txtConstant1.Text == "")
