        // View_Chart()
        //       - View Chart
        // Return Value
        //       - Boolean : True or False
        // Arguments
        //       -
        //
        private bool View_Chart(string sChartID)
        {

            try
            {

                TRSNode in_node = new TRSNode("View_Chart_In");
                TRSNode out_node = new TRSNode("View_Chart_Out");
                bChartViewFlag = true;
                int iGraphType;

                MPCR.SetInMsg(in_node);
                in_node.ProcStep = '1';
                in_node.AddString("CHART_ID", MPCF.Trim(sChartID));

                if (MPCR.CallService("SPC", "SPC_View_Chart", in_node, ref out_node) == false)
                {
                    return false;
                }
                /* Added By YJJung 160217 For Data Initialization */
                init();
                /* Added End */
                txtChart.Text = out_node.GetString("CHART_ID");
                txtDesc.Text = out_node.GetString("CHART_DESC");
                cdvMaterial.Text = out_node.GetString("MAT_ID");
                cdvMaterial.Version = out_node.GetInt("MAT_VER");
                cdvFlow.Text = out_node.GetString("FLOW");
                cdvOper.Text = out_node.GetString("OPER");
                cdvResID.Text = out_node.GetString("RES_ID");
                cdvSubResource.Text = out_node.GetString("SUBRES_ID");
                cdvColSetID.Text = out_node.GetString("COL_SET_ID");
                cdvCharID.Text = out_node.GetString("CHAR_ID");

                cdvProcFlow.Text = out_node.GetString("PROC_FLOW");
                cdvProcOper.Text = out_node.GetString("PROC_OPER");
                cdvProcResID.Text = out_node.GetString("PROC_RES_ID");
                cdvRecipe.Text = out_node.GetString("RECIPE_ID");
                cdvRecipeVer.Text = out_node.GetInt("RECIPE_VERSION") == 0 ? "" : MPCF.Trim(out_node.GetInt("RECIPE_VERSION"));

                cdvGrp1.Text = out_node.GetString("CHT_GRP_1");
                cdvGrp2.Text = out_node.GetString("CHT_GRP_2");
                cdvGrp3.Text = out_node.GetString("CHT_GRP_3");
                cdvGrp4.Text = out_node.GetString("CHT_GRP_4");
                cdvGrp5.Text = out_node.GetString("CHT_GRP_5");
                cdvGrp6.Text = out_node.GetString("CHT_GRP_6");
                cdvGrp7.Text = out_node.GetString("CHT_GRP_7");
                cdvGrp8.Text = out_node.GetString("CHT_GRP_8");
                cdvGrp9.Text = out_node.GetString("CHT_GRP_9");
                cdvGrp10.Text = out_node.GetString("CHT_GRP_10");

                cdvCMF1.Text = out_node.GetString("CHT_CMF_1");
                cdvCMF2.Text = out_node.GetString("CHT_CMF_2");
                cdvCMF3.Text = out_node.GetString("CHT_CMF_3");
                cdvCMF4.Text = out_node.GetString("CHT_CMF_4");
                cdvCMF5.Text = out_node.GetString("CHT_CMF_5");
                cdvCMF6.Text = out_node.GetString("CHT_CMF_6");
                cdvCMF7.Text = out_node.GetString("CHT_CMF_7");
                cdvCMF8.Text = out_node.GetString("CHT_CMF_8");
                cdvCMF9.Text = out_node.GetString("CHT_CMF_9");
                cdvCMF10.Text = out_node.GetString("CHT_CMF_10");

                if (MPCF.Trim(out_node.GetChar("LOT_RES_FLAG")) == "R")
                {
