        // Update_Chart()
        //       - Create/Update/Delete Chart
        // Return Value
        //       - Boolean : True or False
        // Arguments
        //       - ByVal c_step As String : Process Step
        //
        private bool Update_Chart(char c_step)
        {

            try
            {
                TRSNode in_node = new TRSNode("Update_Chart_In");
                TRSNode out_node = new TRSNode("Cmn_Out");
                
                string sRuleCheck;
                int idx;
                int i;
                ListViewItem itm;

                MPCR.SetInMsg(in_node);
                in_node.ProcStep = c_step;
                in_node.AddString("CHART_ID", MPCF.Trim(txtChart.Text));
                in_node.AddString("CHART_DESC", MPCF.Trim(txtDesc.Text));

                if (rbnLot.Checked == true)
                {
                    in_node.AddString("MAT_ID", MPCF.Trim(cdvMaterial.Text));
                    in_node.AddInt("MAT_VER", cdvMaterial.Version);
                    in_node.AddString("FLOW", MPCF.Trim(cdvFlow.Text));
                    in_node.AddString("OPER", MPCF.Trim(cdvOper.Text));
                    in_node.AddString("RES_ID", MPCF.Trim(cdvResID.Text));
                    in_node.AddString("SUBRES_ID", MPCF.Trim(cdvSubResource.Text));
                }
                else if (rbnResource.Checked == true)
                {
                    in_node.AddString("RES_ID", MPCF.Trim(cdvResID.Text));
                    in_node.AddString("SUBRES_ID", MPCF.Trim(cdvSubResource.Text));
                }
                
                in_node.AddString("PROC_FLOW", MPCF.Trim(this.cdvProcFlow.Text));
                in_node.AddString("PROC_OPER", MPCF.Trim(this.cdvProcOper.Text));
                in_node.AddString("PROC_RES_ID", MPCF.Trim(this.cdvProcResID.Text));
                in_node.AddString("MEAS_RES_ID", MPCF.Trim(this.cdvResID.Text));
                in_node.AddString("RECIPE_ID", MPCF.Trim(this.cdvRecipe.Text));
                in_node.AddInt("RECIPE_VERSION", MPCF.Trim(this.cdvRecipeVer.Text) == "" ? 0 : (MPCF.ToInt(this.cdvRecipeVer.Text)));
                in_node.AddString("COL_SET_ID", MPCF.Trim(cdvColSetID.Text));

                in_node.AddChar("SYNC_EDC_FLAG", (chkSyncEDC.Checked == true ? 'Y' : ' '));
                in_node.AddString("CHAR_ID", MPCF.Trim(cdvCharID.Text));
                in_node.AddChar("LOT_RES_FLAG", (rbnLot.Checked == true ? 'L' : 'R'));
                in_node.AddChar("UNIT_USE_FLAG", (chkUseUnit.Checked == true ? 'Y' : ' '));
                if (cboGraphType.SelectedIndex == MPCF.ToInt(eGraphType.P) || cboGraphType.SelectedIndex == MPCF.ToInt(eGraphType.PN) ||
                    cboGraphType.SelectedIndex == MPCF.ToInt(eGraphType.C) || cboGraphType.SelectedIndex == MPCF.ToInt(eGraphType.U))
                {
                    in_node.AddInt("UNIT_COUNT", 1);                    
                }
                else
                {
                    in_node.AddInt("UNIT_COUNT", MPCF.ToInt(txtUnitCount.Text)); 
