                        itm.SubItems.Add(txtDesc.Text);
                        itm.Selected = true;
                        lisChart.Sorting = SortOrder.Ascending;
                        lisChart.Sort();
                        itm.EnsureVisible();
                    }
                    else if (c_step == MPGC.MP_STEP_UPDATE)
                    {
                        if (MPCF.FindListItem(lisChart, MPCF.Trim(txtChart.Text), false) == true)
                        {
                            lisChart.SelectedItems[0].SubItems[1].Text = MPCF.Trim(txtDesc.Text);
                        }
                    }
                    else if (c_step == MPGC.MP_STEP_UNDELETE)
                    {
                        if (chkIncludeDeleteChart.Checked == true)
                        {
                            idx = MPCF.FindListItemIndex(lisChart, MPCF.Trim(txtChart.Text), false);
                            if (idx != -1)
                            {
                                lisChart.Items[idx].ForeColor = Color.Black;

                                MPCR.ChangeControlEnabled(this, btnCreate, true);
                                MPCR.ChangeControlEnabled(this, btnDelete, true);
                                btnUpdate.Text = MPCF.FindLanguage("Update", 1);
                            }
                        }
                    }
                    else if (c_step == MPGC.MP_STEP_DELETE)
                    {
                        idx = MPCF.FindListItemIndex(lisChart, MPCF.Trim(txtChart.Text), false);
                        if (idx != -1)
                        {
                            if (chkIncludeDeleteChart.Checked == true)
                            {
                                lisChart.Items[idx].ForeColor = Color.Magenta;
                                btnCreate.Enabled = false;
                                btnUpdate.Text = MPCF.FindLanguage("Undelete", 1);
                                btnDelete.Enabled = false;
                            }
                            else
                            {
                                lisChart.Items[idx].Remove();
                            }

                        }
                        lblDataCount.Text = lisChart.Items.Count.ToString();
                    }
                }

                return true;

            }
            catch (Exception ex)
            {
                MPCF.ShowMsgBox("frmSPCSetupChart.Update_Chart()\n" + ex.Message);
                return false;
            }

        }

        // View_Spec()
        //       - View Spec
        // Return Value
        //       - Boolean : True or False
        // Arguments
        //       - ByVal iVer As Integer : Version
        //       - Optional ByVal bIgnoreError As Boolean = False : Ignore error flag
        //
        private bool View_Spec(int iVer, bool bIgnoreError)
        {

            try
            {
                TRSNode in_node = new TRSNode("View_Spec_In");
                TRSNode out_node = new TRSNode("View_Spec_Out");

                MPCR.SetInMsg(in_node);
                in_node.ProcStep = '1';
                in_node.AddString("CHART_ID", txtChart.Text);
                in_node.AddInt("VERSION", iVer);

                if (MPCR.CallService("SPC", "SPC_View_Spec", in_node, ref out_node, bIgnoreError) == false)
                {
                    return false;
                }

                if (MPCF.Trim(out_node.GetString("USL")) == "")
                    txtUSL.Text = "";
                else
                    txtUSL.Text = MPCF.ToDbl(out_node.GetString("USL")).ToString();

                if (MPCF.Trim(out_node.GetString("TARGET")) == "")
                    txtTARGET.Text = "";
                else
                    txtTARGET.Text = MPCF.ToDbl(out_node.GetString("TARGET")).ToString();

                if (MPCF.Trim(out_node.GetString("LSL")) == "")
                    txtLSL.Text = "";
                else
                    txtLSL.Text = MPCF.ToDbl(out_node.GetString("LSL")).ToString();


                return true;

            }
            catch (Exception ex)
            {
                MPCF.ShowMsgBox("frmSPCSetupChart.View_Spec()\n" + ex.Message);
                return false;
            }

        }

        private bool View_Resource_ColSet_List(ListView lisList)
        {
            TRSNode in_node = new TRSNode("View_Col_Set_List_In");
            TRSNode out_node;
            ArrayList a_list = new ArrayList(); 
            int i = 0;
            ListViewItem itmX = null;

            try
            {
                MPCF.ClearList(lisList, true);

                MPCR.SetInMsg(in_node);

                in_node.ProcStep = '2';
                in_node.AddString("GRP_TABLE_NAME", MPCF.Trim(cdvResID.Text));
                in_node.AddString("NEXT_COL_SET_ID", "");
                in_node.AddChar("LOT_OR_RES_FLAG", ' ');
                in_node.AddChar("INCLUDE_DEL_FLAG", ' ');


                do
                {
                    out_node = new TRSNode("View_Col_Set_List_Out");
                    if (MPCR.CallService("EDC", "EDC_View_Col_Set_List_By_Group", in_node, ref out_node) == false)
                    {
                        return false;
                    }

                     a_list.Add(out_node);
                                        
                    in_node.SetString("NEXT_COL_SET_ID", out_node.GetString("NEXT_COL_SET_ID"));

                } while (in_node.GetString("NEXT_COL_SET_ID") != "");

                 foreach (object obj in a_list)
                {
                    out_node = null;
                    out_node = (TRSNode)obj;

                    for (i = 0; i < out_node.GetList(0).Count; i++)
                    {
                        itmX = new ListViewItem(MPCF.Trim(out_node.GetList(0)[i].GetString("COL_SET_ID")), (int)SMALLICON_INDEX.IDX_COL_SET);
                        itmX.SubItems.Add(MPCF.Trim(out_node.GetList(0)[i].GetString("COL_SET_DESC")));
                        lisList.Items.Add(itmX);
                    }
                }

            }
            catch (Exception ex)
            {
                MPCF.ShowMsgBox(ex.Message);
                return false;
            }

            return true;
        }

