        // SetConstants()
        //       - Set Constant by Graph type
        // Return Value
        //       - Boolean : True / False
        // Arguments
        //       -
        //
        private void SetConstants()
        {

            try
            {
                int i_sample;
                if (MPCF.Trim(txtSampleSize.Text) == "") return;
                
                if (chkUseUnit.Checked == true || chkSyncEDC.Checked == true)
                {
                    i_sample = MPCF.ToInt(txtSampleSize.Text);
                }
                else
                {
                    /* Updated By YJJung 141110 Unit Count가 입력되지 않은경우(0인 경우포함), 관리도 계수 계산 하지 않는다. */
                    if (MPCF.Trim(txtUnitCount.Text) == "" || MPCF.ToInt(txtUnitCount.Text) < 1) return;
                    /* Added End */
                    i_sample = MPCF.ToInt(txtSampleSize.Text) * MPCF.ToInt(txtUnitCount.Text);
                }
                if (cboGraphType.SelectedIndex == MPCF.ToInt(eGraphType.XBARR))
                {
                    txtConstant1.Text = MPCF.Trim(Miracom.Stat.StatControlConstant.GetControlConstant(StatEnums.CONTROL_CONSTANT._d2, i_sample));
                    txtConstant2.Text = MPCF.Trim(Miracom.Stat.StatControlConstant.GetControlConstant(StatEnums.CONTROL_CONSTANT._d3, i_sample));
                    txtConstant3.Text = MPCF.Trim(Miracom.Stat.StatControlConstant.GetControlConstant(StatEnums.CONTROL_CONSTANT.D3, i_sample));
                    txtConstant4.Text = MPCF.Trim(Miracom.Stat.StatControlConstant.GetControlConstant(StatEnums.CONTROL_CONSTANT.D4, i_sample));

                }
                else if (cboGraphType.SelectedIndex == MPCF.ToInt(eGraphType.XBARS))
                {
                    txtConstant1.Text = MPCF.Trim(Miracom.Stat.StatControlConstant.GetControlConstant(StatEnums.CONTROL_CONSTANT._c4, i_sample));
                    txtConstant2.Text = MPCF.Trim(Miracom.Stat.StatControlConstant.GetControlConstant(StatEnums.CONTROL_CONSTANT.A3, i_sample));
                    txtConstant3.Text = (MPCF.ToInt(Miracom.Stat.StatControlConstant.GetControlConstant(StatEnums.CONTROL_CONSTANT.B3, i_sample)) < 0) ? "0" : MPCF.Trim(Miracom.Stat.StatControlConstant.GetControlConstant(StatEnums.CONTROL_CONSTANT.B3, i_sample));
                    txtConstant4.Text = MPCF.Trim(Miracom.Stat.StatControlConstant.GetControlConstant(StatEnums.CONTROL_CONSTANT.B4, i_sample));

                }
                else if (cboGraphType.SelectedIndex == MPCF.ToInt(eGraphType.XRS))
                {
                    txtConstant1.Text = MPCF.Trim(Miracom.Stat.StatControlConstant.GetControlConstant(StatEnums.CONTROL_CONSTANT._d2, 2));
                    txtConstant2.Text = MPCF.Trim(Miracom.Stat.StatControlConstant.GetControlConstant(StatEnums.CONTROL_CONSTANT.D3, 2));
                    txtConstant3.Text = MPCF.Trim(Miracom.Stat.StatControlConstant.GetControlConstant(StatEnums.CONTROL_CONSTANT.D4, 2));
                }
                else if (cboGraphType.SelectedIndex == MPCF.ToInt(eGraphType.ZBARS))
                {
                    txtConstant1.Text = MPCF.Trim(Miracom.Stat.StatControlConstant.GetControlConstant(StatEnums.CONTROL_CONSTANT._c4, i_sample));
                    txtConstant2.Text = (MPCF.ToInt(Miracom.Stat.StatControlConstant.GetControlConstant(StatEnums.CONTROL_CONSTANT.B3, i_sample)) < 0) ? "0" : MPCF.Trim(Miracom.Stat.StatControlConstant.GetControlConstant(StatEnums.CONTROL_CONSTANT.B3, i_sample));
                    txtConstant3.Text = MPCF.Trim(Miracom.Stat.StatControlConstant.GetControlConstant(StatEnums.CONTROL_CONSTANT.B4, i_sample));

                }
                else if (cboGraphType.SelectedIndex == MPCF.ToInt(eGraphType.DELTAS))
                {
                    txtConstant1.Text = MPCF.Trim(Miracom.Stat.StatControlConstant.GetControlConstant(StatEnums.CONTROL_CONSTANT._c4, i_sample));
                    txtConstant2.Text = MPCF.Trim(Miracom.Stat.StatControlConstant.GetControlConstant(StatEnums.CONTROL_CONSTANT.A3, i_sample));
                    txtConstant3.Text = (MPCF.ToInt(Miracom.Stat.StatControlConstant.GetControlConstant(StatEnums.CONTROL_CONSTANT.B3, i_sample)) < 0) ? "0" : MPCF.Trim(Miracom.Stat.StatControlConstant.GetControlConstant(StatEnums.CONTROL_CONSTANT.B3, i_sample));
                    txtConstant4.Text = MPCF.Trim(Miracom.Stat.StatControlConstant.GetControlConstant(StatEnums.CONTROL_CONSTANT.B4, i_sample));

                }

            }
            catch (Exception ex)
            {
                MPCF.ShowMsgBox("frmSPCSetupChart.SetConstants()\n" + ex.Message);
            }

        }

        // View_Col_Set()
        //       - Set Constant by Graph type
        // Return Value
        //       - Boolean : True / False
        // Arguments
        //       - ByVal sColSetID As String : Collection Set ID
        //       - ByRef bBothType As Boolean : Collection Set Type Flag
        //
        private bool View_Col_Set(string sColSetID, ref bool bBothType)
        {

            TRSNode in_node = new TRSNode("View_Col_Set_In");
            TRSNode out_node = new TRSNode("View_Col_Set_Out");
            
            try
            {
                MPCR.SetInMsg(in_node);
                in_node.ProcStep = '1';
                in_node.AddString("COL_SET_ID", MPCF.Trim(sColSetID));

                if (MPCR.CallService("EDC", "EDC_View_Col_Set", in_node, ref out_node) == false)
                {
                    return false;
                }

                if (MPCF.Trim(out_node.GetChar("LOT_OR_RES_FLAG")) == "B")
                {
                    bBothType = true;
                }
                else
                {
                    bBothType = false;
                }

                return true;

            }
            catch (Exception ex)
            {
                MPCF.ShowMsgBox("frmSPCSetupChart.View_Col_Set()\n" + ex.Message);
                return false;
            }

        }

