        // SetRuleControls()
        //       -
        // Return Value
        //       -
        // Arguments
        //       -
        //
        private void SetRuleControls(Panel pnlRule)
        {
            TRSNode out_node = new TRSNode("Set_Rule_Controls");
            try
            {
                Control ctrl;

                foreach (Control tempLoopVar_ctrl in pnlRule.Controls)
                {
                    ctrl = tempLoopVar_ctrl;
                    if (MPCF.Trim(ctrl.Tag) != "")
                    {
                        if (MPCF.SetRuleDescription(MPCF.ToChar(ctrl.Tag), out_node) == "")
                        {
                            ctrl.Visible = false;
                        }
                        else
                        {
                            if (MPCF.CheckNumeric(ctrl.Name.Substring(8)) == true && (ctrl.Name.Substring(0, 8) == "lblXRule" || ctrl.Name.Substring(0, 8) == "lblRRule"))
                            {
                                ctrl.Text = MPCF.SetRuleDescription(MPCF.ToChar(ctrl.Tag), out_node);
                            }
                            ctrl.Visible = true;
                        }
                    }
                }

            }
            catch (Exception ex)
            {
                MPCF.ShowMsgBox("frmSPCSetupChart.SetRuleControls()\n" + ex.Message);
            }

        }

