        private void CheckConstant()
        {
            try
            {
                if (MPCF.Trim(txtSampleSize.Text) == "") return;
                if (chkSyncEDC.Checked == false && MPCF.Trim(txtUnitCount.Text) == "")
                {
                    return;
                }

                if (cboGraphType.SelectedIndex != MPCF.ToInt(eGraphType.XRS))
                {
                    //if (chkUseUnit.Checked == true || chkSyncEDC.Checked == true)
                    if (chkSyncEDC.Checked == true)
                    {
                        if (MPCF.ToInt(txtSampleSize.Text) < 2)
                        {
                            txtSampleSize.Focus();
                            if (MPGV.gcLanguage == '2')
                            {
                                MPCF.ShowMsgBox(MPCF.GetErrorMsgParse(234, "\'2\' ") + MPCF.GetMessage(234));
                            }
                            else
                            {
                                MPCF.ShowMsgBox(MPCF.GetMessage(234) + " \'2\'");
                            }
                            txtSampleSize.Focus();
                            return;
                        }
                    }
                    else
                    {
                        /* Added By YJJung 141030 SyncEDCFlag가 false인 경우, Unit Count 가 1보다 작은경우는 Error Message 발생. */
                        if (MPCF.ToInt(txtUnitCount.Text) < 1)
                        {
                            txtUnitCount.Focus();
                            MPCF.ShowMsgBox(MPCF.GetMessage(141));
                            return;
                        }
                        /* Added End */
                        else if (MPCF.ToInt(txtSampleSize.Text) * MPCF.ToInt(txtUnitCount.Text) < 2)
                        {
                            txtSampleSize.Focus();
                            if (MPGV.gcLanguage == '2')
                            {
                                MPCF.ShowMsgBox(MPCF.GetErrorMsgParse(234, "\'2\' ") + MPCF.GetMessage(234));
                            }
                            else
                            {
                                MPCF.ShowMsgBox(MPCF.GetMessage(234) + " \'2\'");
                            }
                            txtSampleSize.Focus();
                            return;
                        }
                    }

                    if (MPCF.ToInt(txtSampleSize.Text) > 1000)
                    {
                        txtSampleSize.Text = "";
                        txtSampleSize.Focus();
                        if (MPGV.gcLanguage == '2')
                        {
                            MPCF.ShowMsgBox(MPCF.GetErrorMsgParse(236, "\'1000\' ") + MPCF.GetMessage(236));
                        }
                        else
                        {
                            MPCF.ShowMsgBox(MPCF.GetMessage(236) + " \'1000\'");
                        }
                        txtSampleSize.Focus();
                        return;
                    }
                }
                SetConstants();
            }
            catch (Exception ex)
            {
                MPCF.ShowMsgBox("frmSPCSetupChart.InitCodeView()\n" + ex.Message);
            }
        }
