            }

        }

        private void btnCreate_Click(System.Object sender, System.EventArgs e)
        {

            try
            {

                if (CheckCondition(MPGC.MP_STEP_CREATE) == false)
                {
                    return;
                }
                if (Update_Chart(MPGC.MP_STEP_CREATE) == false)
                {
                    return;
                }
                if (MPGV.gbListAutoRefresh == true)
                {
                    btnRefresh.PerformClick();
                }


            }
            catch (Exception ex)
            {
                MPCF.ShowMsgBox("frmSPCSetupChart.btnCreate_Click()\n" + ex.Message);
            }

        }

        private void btnUpdate_Click(object sender, System.EventArgs e)
        {

            try
            {
                if (btnUpdate.Text == MPCF.FindLanguage("Update", 1))
                {
                    if (CheckCondition(MPGC.MP_STEP_CREATE) == false)
                    {
                        return;
                    }
                    if (Update_Chart(MPGC.MP_STEP_UPDATE) == false)
                    {
                        return;
                    }
                    if (MPGV.gbListAutoRefresh == true)
                    {
                        btnRefresh.PerformClick();
                    }

                }
                else if (btnUpdate.Text == MPCF.FindLanguage("Undelete", 1))
                {
                    if (MPCF.ShowMsgBox(MPCF.GetMessage(208), MessageBoxButtons.YesNo, 1) == System.Windows.Forms.DialogResult.Yes)
                    {
                        if (CheckCondition(MPGC.MP_STEP_UNDELETE) == false)
                        {
                            return;
                        }
                        if (Update_Chart(MPGC.MP_STEP_UNDELETE) == false)
                        {
                            return;
                        }
                        if (MPGV.gbListAutoRefresh == true)
                        {
                            btnRefresh.PerformClick();
                        }
                    }
                    else
                    {
                        return;
                    }
                }

            }
            catch (Exception ex)
            {
                MPCF.ShowMsgBox("frmSPCSetupChart.btnUpdate_Click()\n" + ex.Message);
            }

        }

        private void btnDelete_Click(object sender, System.EventArgs e)
        {

            try
            {
                if (CheckCondition(MPGC.MP_STEP_DELETE) == false)
                {
                    return;
                }
                if (MPCF.ShowMsgBox(MPCF.GetMessage(54), MessageBoxButtons.YesNo, 1) != System.Windows.Forms.DialogResult.Yes)
                {
                    return;
                }
                if (Update_Chart(MPGC.MP_STEP_DELETE) == false)
                {
                    return;
                }
                MPCF.FieldClear(this.pnlRight);
                if (MPGV.gbListAutoRefresh == true)
                {
                    btnRefresh.PerformClick();
                }

            }
            catch (Exception ex)
            {
                MPCF.ShowMsgBox("frmSPCSetupChart.btnDelete_Click()\n" + ex.Message);
            }

        }

        private void btnRefresh_Click(System.Object sender, System.EventArgs e)
        {

            try
            {
                lblDataCount.Text = "";
                if (rbnAll.Checked == false && rbnFilter.Checked == false)
                {
                    rbnAll.Checked = true;
                }
                if (rbnFilter.Checked == true && MPCF.Trim(txtFilter.Text) == "")
                {
                    lisChart.Items.Clear();
                    lblDataCount.Text = lisChart.Items.Count.ToString();
                    return;
                }
                if (SPCLIST.ViewChartList(lisChart, '1', "", 0, "", "", "", ' ', (chkIncludeDeleteChart.Checked ? 'Y' : ' '), (rbnAll.Checked == true ? "" : (MPCF.Trim(txtFilter.Text))), "", -1, -1, null, "") == true)
                {
                    lblDataCount.Text = lisChart.Items.Count.ToString();
                    //If lisChart.Items.Count > 0 Then
                    //    lisChart.Items.Item(0).Selected = True
                    //End If
                }
                if (lisChart.Items.Count > 0)
                {
                    MPCF.FindListItem(lisChart, txtChart.Text, false);
                }

            }
            catch (Exception ex)
            {
                MPCF.ShowMsgBox("frmSPCSetupChart.btnRefresh_Click()\n" + ex.Message);
            }

        }

