        private void rbnLot_CheckedChanged(object sender, System.EventArgs e)
        {

            try
            {
                if (rbnLot.Checked == true)
                {
                    /* 필수 입력 없앰 - LAVERWON (2008/02/22)
                    this.cdvMaterial.LabelFont = new System.Drawing.Font(cdvMaterial.Font, System.Drawing.FontStyle.Bold);
                    lblResID.Font = new System.Drawing.Font(lblResID.Font, System.Drawing.FontStyle.Regular);
                     */
                    cdvMaterial.Enabled = true;
                    cdvFlow.Enabled = true;
                    cdvOper.Enabled = true;
                    cdvProcFlow.Enabled = true;
                    cdvProcOper.Enabled = true;
                    cdvProcResID.Enabled = true;
                    lblFlow.Enabled = true;
                    lblOper.Enabled = true;
                    lblProcFlow.Enabled = true;
                    lblProcOper.Enabled = true;
                    lblProcResID.Enabled = true;                    
                    /* LAVERWON (2008/02/22)
                    cdvRecipe.Enabled = true;
                    cdvRecipeVer.Enabled = true;
                     */
                    
                }
                else if (rbnResource.Checked == true)
                {
                    /* 필수 입력 없앰 - LAVERWON (2008/02/22)
                    this.cdvMaterial.LabelFont = new System.Drawing.Font(cdvMaterial.Font, System.Drawing.FontStyle.Regular);
                    lblResID.Font = new System.Drawing.Font(lblResID.Font, System.Drawing.FontStyle.Bold);
                     */
                    
                    cdvMaterial.ClearField();
                    cdvFlow.Text = "";
                    cdvOper.Text = "";
                    cdvProcFlow.Text = "";
                    cdvProcOper.Text = "";
                    cdvProcResID.Text = "";
                    /* LAVERWON (2008/02/22)
                    cdvRecipe.Text = "";
                    cdvRecipeVer.Text = "";
                     */
                    cdvMaterial.Enabled = false;
                    cdvFlow.Enabled = false;
                    cdvOper.Enabled = false;
                    cdvProcFlow.Enabled = false;
                    cdvProcOper.Enabled = false;
                    cdvProcResID.Enabled = false;
                    lblFlow.Enabled = false;
                    lblOper.Enabled = false;
                    lblProcFlow.Enabled = false;
                    lblProcOper.Enabled = false;
                    lblProcResID.Enabled = false;      
                    /* LAVERWON (2008/02/22)
                    cdvRecipe.Enabled = true;
                    cdvRecipeVer.Enabled = true;
                     */
                    
                }

            }
            catch (Exception ex)
            {
                MPCF.ShowMsgBox("frmSPCSetupChart.rbnLot_CheckedChanged()\n" + ex.Message);
            }

        }

