        private void cboGraphType_SelectionChanged(object sender, System.EventArgs e)
        {

            try
            {
                /* Default Check 없앰 
                chkXRule1.Checked = true;
                chkXRule2.Checked = true;
                chkRRule2.Checked = true;
                 */

                if (cboGraphType.SelectedIndex == MPCF.ToInt(eGraphType.P) ||
                    cboGraphType.SelectedIndex == MPCF.ToInt(eGraphType.PN) ||
                    cboGraphType.SelectedIndex == MPCF.ToInt(eGraphType.C) ||
                    cboGraphType.SelectedIndex == MPCF.ToInt(eGraphType.U))
                {
                    pnlRRuleType.Visible = false;
                    pnlRRuleType.Tag = " ";
                }
                else
                {
                    pnlRRuleType.Visible = true;
                    pnlRRuleType.Tag = "T";
                }
                if (cboGraphType.SelectedIndex == MPCF.ToInt(eGraphType.XBARR) ||
                    cboGraphType.SelectedIndex == MPCF.ToInt(eGraphType.XBARS))
                {
                    cboSigmaWB.ReadOnly = false;
                }
                else
                {
                    cboSigmaWB.ReadOnly = true;
                }

                if (SetSPCGraphType() == false)
                {
                    return;
                }

                SetConstants();

            }
            catch (Exception ex)
            {
                MPCF.ShowMsgBox("frmSPCSetupChart.cboGraphType_SelectionChanged()\n" + ex.Message);
            }

        }

        private void txtNumber_KeyPress(object sender, System.Windows.Forms.KeyPressEventArgs e)
        {

            try
            {
                if (e.KeyChar != (char)13 && e.KeyChar != (char)8)
                {
                    if (e.KeyChar < (char)48 || e.KeyChar > (char)57)
                    {
                        if (e.KeyChar == (char)46)
                        {
                            if (((UltraTextEditor)sender).Text == "" || ((UltraTextEditor)sender).Text.Contains(".") == true)
                            {
                                e.Handled = true;
                            }
                        }
                        else if (e.KeyChar == (char)45)
                        {
                            if (((UltraTextEditor)sender).Text != "" || ((UltraTextEditor)sender).Text.Contains("-") == true)
                            {
                                e.Handled = true;
                            }
                        }
                        else
                        {
                            e.Handled = true;
                        }
                    }
                }

            }
            catch (Exception ex)
            {
                MPCF.ShowMsgBox("frmSPCSetupChart.txtNumber_KeyPress()\n" + ex.Message);
            }

        }

