        private void cdvProcFlow_ButtonPress(object sender, EventArgs e)
        {
            try
            {
                cdvProcFlow.Init();
                MPCF.InitListView(cdvProcFlow.GetListView);
                cdvProcFlow.Columns.Add("Flow", 50, HorizontalAlignment.Left);
                cdvProcFlow.Columns.Add("Desc", 100, HorizontalAlignment.Left);
                cdvProcFlow.SelectedSubItemIndex = 0;
                if (MPCF.Trim(cdvMaterial.Text) == "")
                {
                    if (WIPLIST.ViewFlowList(cdvProcFlow.GetListView, '1', "", 0, "", null, "") == false)
                    {
                        return;
                    }
                }
                else
                {
                    if (WIPLIST.ViewFlowList(cdvProcFlow.GetListView, '2', cdvMaterial.Text, cdvMaterial.Version, "", null, "") == false)
                    {
                        return;
                    }
                }

                cdvProcFlow.AddEmptyRow(1);

            }
            catch (Exception ex)
            {
                MPCF.ShowMsgBox("frmSPCSetupChart.cdvProcFlow_ButtonPress()\n" + ex.Message);
            }
        }
        private void cdvProcOper_ButtonPress(System.Object sender, System.EventArgs e)
        {

            try
            {
               
                cdvProcOper.Init();
                MPCF.InitListView(cdvProcOper.GetListView);
                cdvProcOper.Columns.Add("Operation", 50, HorizontalAlignment.Left);
                cdvProcOper.Columns.Add("Desc", 100, HorizontalAlignment.Left);
                cdvProcOper.SelectedSubItemIndex = 0;
                if (cdvMaterial.Text != "" && cdvProcFlow.Text != "")
                {
                    if (WIPLIST.ViewOperationList(cdvProcOper.GetListView, '4', cdvMaterial.Text, cdvMaterial.Version, cdvProcFlow.Text, "", null, "") == false)
                    {
                        return;
                    }
                }
                else if (cdvMaterial.Text == "" && cdvProcFlow.Text != "")
                {
                    if (WIPLIST.ViewOperationList(cdvProcOper.GetListView, '2', "", 0, cdvProcFlow.Text, "", null, "") == false)
                    {
                        return;
                    }
                }
                else if (cdvMaterial.Text != "" && cdvProcFlow.Text == "")
                {
                    if (WIPLIST.ViewOperationList(cdvProcOper.GetListView, '3', cdvMaterial.Text, cdvMaterial.Version, "", "", null, "") == false)
                    {
                        return;
                    }
                }
                else if (cdvMaterial.Text == "" && cdvProcFlow.Text == "")
                {
                    if (WIPLIST.ViewOperationList(cdvProcOper.GetListView, '1', "", 0, "", "", null, "") == false)
                    {
                        return;
                    }
                }
                cdvProcOper.AddEmptyRow(1);

            }
            catch (Exception ex)
            {
                MPCF.ShowMsgBox("frmSPCSetupChart.cdvProcOper_ButtonPress()\n" + ex.Message);
            }

        }

